        description: "List of community engagement or volunteer work."
    }
  }
};

export const parseResume = async (base64Data: string, mimeType: string): Promise<Partial<FullProfileData>> => {
  const prompt = `
    Analyze this resume document and extract data into the structured JSON format.

    **CRITICAL DATE INSTRUCTIONS:**
    - Standardize all dates to **YYYY-MM-DD** format (e.g., "January 2023" -> "2023-01-01").
    - If a date is "Present" or "Current", mark 'is_current_job' as true and leave end dates null.
    - For employment 'date_hired', use the Start Date of the role.

    **EXTRACTION RULES:**
    1. **Personal**: Extract Name, Contact, and Address.
    2. **Education**: Concatenate schools if multiple exist for a level (e.g., "School A / School B").
    3. **Employment**: Extract ALL history. 
       - Infer 'employment_status' (usually 'Employed' for corporate jobs).
       - Infer 'position' and 'company_name'.
       - If the job seems to be a personal business, set status to 'Self-employed'.
    4. **Community**: Extract volunteer experience or org affiliations.

    If a field is not explicitly found, return null or empty string.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Data } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: fullResumeSchema
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text);
      // Ensure arrays are initialized
      return {
        ...data,
        employment: data.employment || [],
        community: data.community || [],
        attributes: {} 
      };
    }
    throw new Error("AI extraction failed");
  } catch (error) {
    console.error("Resume Parsing Error:", error);
    throw new Error("Failed to parse resume. Please enter data manually.");
  }
};

export const uploadResumeToDB = async (file: File, userId: string, userType: 'graduating' | 'alumni' | 'student') => {
  const buffer = await file.arrayBuffer();
  const byteArray = new Uint8Array(buffer);
  let hexString = '\\x';
  for (let i = 0; i < byteArray.length; i++) {
    hexString += byteArray[i].toString(16).padStart(2, '0');
  }

  const targetTable = (userType === 'alumni') ? 'alumni' : 'students';

  const { error } = await supabase
    .from(targetTable)
    .update({ resume: hexString })
    .eq('id', userId);

  if (error) throw error;
};

export const deleteResumeFromDB = async (userId: string, userType: 'graduating' | 'alumni' | 'student') => {
    const targetTable = (userType === 'alumni') ? 'alumni' : 'students';
    const { error } = await supabase
        .from(targetTable)
        .update({ resume: null })
        .eq('id', userId);
    if (error) throw error;
};

// --- DATA PERSISTENCE & FETCHING ---

export const fetchLatestProfile = async (userId: string, userType: 'graduating' | 'alumni' | 'student'): Promise<FullProfileData | null> => {
    const idColumn = userType === 'graduating' ? 'student_id' : 'alumni_id';

    // 1. Get the most recent survey response ID
    const { data: latestSurvey, error: surveyError } = await supabase
        .from('survey_responses')
        .select('id')
        .eq(idColumn, userId)
        .order('submitted_at', { ascending: false })
        .limit(1)
        .single();

    if (surveyError || !latestSurvey) {
        return null; // No profile data saved yet
    }

    const surveyId = latestSurvey.id;

    // 2. Fetch related data in parallel
    const [education, employment, community, attributes] = await Promise.all([
        supabase.from('education_information').select('*').eq('survey_response_id', surveyId).single(),
        supabase.from('employment_history').select('*').eq('survey_response_id', surveyId),
        supabase.from('community_engagement').select('*').eq('survey_response_id', surveyId),
        supabase.from('alumni_attributes').select('*').eq('survey_response_id', surveyId).single()
    ]);

    return {
        education: education.data || {},
        employment: employment.data || [],
        community: community.data || [],
        attributes: attributes.data || {
            communication_skills: 0,
            problem_solving: 0,
            technical_skills: 0,
            teamwork: 0,
            leadership: 0,
            ethics: 0
        }
    };
};

export const updateUserAddress = async (userId: string, userType: 'graduating' | 'alumni' | 'student', address: string) => {
    const targetTable = (userType === 'alumni') ? 'alumni' : 'students';
    const { error } = await supabase
        .from(targetTable)
        .update({ address: address })
        .eq('id', userId);

    if (error) throw error;
};

export const saveProfileData = async (
  userId: string, 
  userType: 'graduating' | 'alumni' | 'student', 
  data: FullProfileData
) => {
  // 1. Create Survey Response (Acts as a snapshot/history record)
  const respondentType = userType === 'graduating' ? 'student' : 'alumni';
  const surveyPayload: any = {
    respondent_type: respondentType,
    submitted_at: new Date().toISOString()
  };

  if (respondentType === 'student') surveyPayload.student_id = userId;
  else surveyPayload.alumni_id = userId;

  const { data: surveyData, error: surveyError } = await supabase
    .from('survey_responses')
    .insert([surveyPayload])
    .select()
    .single();

  if (surveyError) throw surveyError;
  const surveyId = surveyData.id;

  // 2. Insert Education Information (Single Entry)
  if (data.education) {
    // Remove ID if present to avoid conflict on insert
    const { id, ...eduData } = data.education as any; 
    const { error: eduError } = await supabase
      .from('education_information')
      .insert([{ ...eduData, survey_response_id: surveyId }]);
    if (eduError) console.error("Education Save Error", eduError);
  }

  // 3. Insert Employment History (Multiple Entries)
  if (data.employment && data.employment.length > 0) {
    const employmentRecords = data.employment.map(emp => {
        const { id, ...empData } = emp as any;
        return { ...empData, survey_response_id: surveyId };
    });
    const { error: empError } = await supabase
      .from('employment_history')
      .insert(employmentRecords);
    if (empError) console.error("Employment Save Error", empError);
  }

  // 4. Insert Community Engagement (Multiple Entries)
  if (data.community && data.community.length > 0) {
    const validCommunity = data.community.filter(c => c.organization_name).map(com => {
        const { id, ...comData } = com as any;
        return { ...comData, survey_response_id: surveyId };
    });

    if (validCommunity.length > 0) {
        const { error: commError } = await supabase
          .from('community_engagement')
          .insert(validCommunity);
        if (commError) console.error("Community Save Error", commError);
    }
  }

  // 5. Insert Alumni Attributes (Manual Ratings)
  if (data.attributes) {
    const { id, ...attrData } = data.attributes as any;
    const { error: attrError } = await supabase
      .from('alumni_attributes')
      .insert([{ ...attrData, survey_response_id: surveyId }]);
    if (attrError) console.error("Attributes Save Error", attrError);
  }

  return true;
};

