}

const MyProfilePage: React.FC<MyProfilePageProps> = ({ user }) => {
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);
  const [parsing, setParsing] = useState(false);
  const [resumeUploaded, setResumeUploaded] = useState(!!user.resume);
  const [savedSuccess, setSavedSuccess] = useState(false);
  const [activeSection, setActiveSection] = useState<string | null>(null); // Closed by default since header has info
  const [verificationWarning, setVerificationWarning] = useState<string | null>(null);

  // Editable Personal Information State
  const [firstName, setFirstName] = useState(user.first_name);
  const [lastName, setLastName] = useState(user.last_name);
  const [email, setEmail] = useState(user.email);
  const [contactNo, setContactNo] = useState(user.contact_no);
  const [address, setAddress] = useState(user.address || '');
  const [program, setProgram] = useState(user.program);
  const [yearLevel, setYearLevel] = useState(user.year_level || '');

  // Profile Data State (Employment, Education, etc.)
  const [profileData, setProfileData] = useState<FullProfileData>({
    education: {},
    employment: [],
    community: [],
    attributes: {
        communication_skills: 0,
        problem_solving: 0,
        technical_skills: 0,
        teamwork: 0,
        leadership: 0,
        ethics: 0
    }
  });

  // Load latest profile data on mount
  useEffect(() => {
    const loadData = async () => {
        if (!user.id) return;
        try {
            const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';
            const data = await fetchLatestProfile(user.id, userType);
            if (data) {
                setProfileData(data);
            }
        } catch (error) {
            console.error("Failed to load profile", error);
        } finally {
            setFetching(false);
        }
    };
    loadData();
  }, [user.id]);

  const handleResumeUpload = async (file: File) => {
    setParsing(true);
    setVerificationWarning(null);

    try {
        const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';

        // 1. Upload Raw File
        await uploadResumeToDB(file, user.id!, userType);
        setResumeUploaded(true);

        // 2. Parse Data
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = async () => {
            const base64Data = (reader.result as string).split(',')[1];
            try {
                const extracted = await parseResume(base64Data, file.type);

                // Verification Logic
                if (extracted.personal) {
                    const extractedLast = extracted.personal.last_name?.toLowerCase() || '';
                    const userLast = lastName.toLowerCase();
                    if (extractedLast && !extractedLast.includes(userLast)) {
                        setVerificationWarning(`Warning: The name on the resume (${extracted.personal.first_name} ${extracted.personal.last_name}) does not match your account name.`);
                    }
                    // Auto-fill address/contact if found
                    if (extracted.personal.address && !address) setAddress(extracted.personal.address);
                    if (extracted.personal.contact_no && !contactNo) setContactNo(extracted.personal.contact_no);
                    if (extracted.personal.email && !email) setEmail(extracted.personal.email);
                }

                setProfileData(prev => ({
                    ...prev,
                    education: { ...prev.education, ...extracted.education },
                    // Append extracted employment/community to existing
                    employment: [...(prev.employment || []), ...(extracted.employment || [])],
                    community: [...(prev.community || []), ...(extracted.community || [])],
                }));
            } catch (err) {
                console.error(err);
                alert("Could not parse resume details automatically. Please fill details manually.");
            } finally {
                setParsing(false);
            }
        };
    } catch (error) {
        console.error("Upload error:", error);
        alert("Failed to upload resume.");
        setParsing(false);
    }
  };

  const handleDeleteResume = async () => {
      if(!confirm("Are you sure you want to delete your resume file?")) return;
      try {
          const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';
          await deleteResumeFromDB(user.id!, userType);
          setResumeUploaded(false);
          alert("Resume file deleted from system.");
      } catch (e) {
          console.error(e);
          alert("Failed to delete resume.");
      }
  };

  const handleInputChange = (section: keyof FullProfileData, field: string, value: any) => {
    setProfileData(prev => ({
        ...prev,
        [section]: {
            ...prev[section],
            [field]: value
        }
    }));
  };

  // --- Employment List Handlers ---
  const addEmployment = () => {
      setProfileData(prev => ({
          ...prev,
          employment: [{ employment_status: 'Employed', is_current_job: false }, ...prev.employment]
      }));
  };

  const removeEmployment = (index: number) => {
      const newEmp = [...profileData.employment];
      newEmp.splice(index, 1);
      setProfileData(prev => ({ ...prev, employment: newEmp }));
  };

  const updateEmployment = (index: number, field: keyof EmploymentHistory, value: any) => {
      const newEmp = [...profileData.employment];
      newEmp[index] = { ...newEmp[index], [field]: value };
      setProfileData(prev => ({ ...prev, employment: newEmp }));
  };

  // --- Community List Handlers ---
  const addCommunity = () => {
      setProfileData(prev => ({
          ...prev,
          community: [{}, ...prev.community]
      }));
  };

  const removeCommunity = (index: number) => {
      const newComm = [...profileData.community];
      newComm.splice(index, 1);
      setProfileData(prev => ({ ...prev, community: newComm }));
  };

  const updateCommunity = (index: number, field: keyof CommunityEngagement, value: any) => {
      const newComm = [...profileData.community];
      newComm[index] = { ...newComm[index], [field]: value };
      setProfileData(prev => ({ ...prev, community: newComm }));
  };


  const handleSaveProfile = async () => {
    setLoading(true);
    try {
        const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';

        // 1. Update Core User Details (Students/Alumni Table)
        await updateStudentProfile(user.id!, userType, {
            first_name: firstName,
            last_name: lastName,
            email: email,
            contact_no: contactNo,
            address: address,
            program: program,
            year_level: yearLevel
        });

        // 2. Save Survey Response Data (Education, Employment, etc.)
        await saveProfileData(user.id!, userType, profileData);

        setSavedSuccess(true);
        setTimeout(() => setSavedSuccess(false), 3000);
    } catch (error) {
        console.error("Save error:", error);
        alert("Failed to save profile.");
    } finally {
        setLoading(false);
    }
  };

  const toggleSection = (section: string) => {
      setActiveSection(activeSection === section ? null : section);
  };

  // Render Helpers
  const renderInput = (section: keyof FullProfileData, field: string, label: string, type: string = "text", placeholder: string = "") => (
      <div className="space-y-1">
          <label className="text-xs font-bold text-gray-500 uppercase">{label}</label>
          <input 
            type={type} 
            value={(profileData[section] as any)[field] || ''} 
            onChange={(e) => handleInputChange(section, field, e.target.value)}
            className="w-full px-4 py-2.5 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none text-sm"
            placeholder={placeholder}
          />
      </div>
  );

  const renderRating = (field: string, label: string) => (
      <div className="flex items-center justify-between p-3 bg-gray-50 rounded-xl">
          <span className="text-sm font-bold text-gray-700">{label}</span>
          <div className="flex gap-1">
              {[1, 2, 3, 4, 5].map((star) => (
                  <button 
                    key={star} 
                    type="button"
                    onClick={() => handleInputChange('attributes', field, star)}
                    className={`p-1 rounded-full transition-colors ${
                        (profileData.attributes as any)[field] >= star ? 'text-yellow-400' : 'text-gray-300 hover:text-yellow-200'
                    }`}
                  >
                      <Star size={20} fill={(profileData.attributes as any)[field] >= star ? "currentColor" : "none"} />
                  </button>
              ))}
          </div>
      </div>
  );

  if (fetching) {
      return (
          <div className="bg-white rounded-3xl shadow-sm border border-gray-100 min-h-[500px] flex items-center justify-center">
              <div className="flex flex-col items-center">
                  <Loader2 className="w-8 h-8 animate-spin text-luGreen mb-2" />
                  <p className="text-gray-500 text-sm">Loading profile data...</p>
              </div>
          </div>
      );
  }

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden animate-slide-up relative min-h-[500px]">

        {/* Profile Header Card */}
        <div className="relative">
            {/* Banner Background */}
            <div className="h-48 bg-gradient-to-r from-luGreen-dark via-luGreen to-emerald-600 relative overflow-hidden">
                <div className="absolute inset-0 bg-black/10"></div>
                <div className="absolute -right-10 -top-10 w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
                <div className="absolute -left-10 -bottom-10 w-64 h-64 bg-luGold/20 rounded-full blur-3xl"></div>
                <div className="absolute top-6 right-8">
                     {savedSuccess && (
                        <div className="flex items-center gap-2 text-white font-bold bg-white/20 backdrop-blur-md px-4 py-2 rounded-full animate-fade-in border border-white/30 shadow-lg">
                            <CheckCircle size={18} /> Saved Successfully
                        </div>
                    )}
                </div>
            </div>

            {/* Profile Info Overlay */}
            <div className="px-8 pb-8 relative">
                <div className="flex flex-col md:flex-row items-end -mt-16 gap-6 mb-6">
                     {/* Avatar */}
                     <div className="relative group">
                        <div className="w-32 h-32 rounded-3xl bg-white p-1.5 shadow-xl rotate-3 group-hover:rotate-0 transition-transform duration-500">
                             <div className="w-full h-full rounded-2xl bg-gray-100 flex items-center justify-center text-gray-300 overflow-hidden border border-gray-200">
                                <User size={64} className="opacity-50" />
                            </div>
                        </div>
                        <div className="absolute -bottom-2 -right-2 bg-luGold text-white p-2 rounded-full shadow-md border-2 border-white">
                            <Edit3 size={16} />
                        </div>
                     </div>

                     {/* Primary Name Edit */}
                     <div className="flex-grow space-y-1 mb-2">
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                value={firstName} 
                                onChange={(e) => setFirstName(e.target.value)}
                                className="bg-transparent border-b-2 border-transparent hover:border-gray-300 focus:border-luGreen focus:outline-none text-3xl font-bold text-gray-800 font-display w-full md:w-auto placeholder-gray-400"
                                placeholder="First Name"
                            />
                            <input 
                                type="text" 
                                value={lastName} 
                                onChange={(e) => setLastName(e.target.value)}
                                className="bg-transparent border-b-2 border-transparent hover:border-gray-300 focus:border-luGreen focus:outline-none text-3xl font-bold text-gray-800 font-display w-full md:w-auto placeholder-gray-400"
                                placeholder="Last Name"
                            />
                        </div>
                        <p className="text-sm text-gray-500 font-medium">Student No: <span className="font-mono text-luGreen">{user.student_number}</span></p>
                     </div>

                     {/* Program / Status Edit */}
                     <div className="flex flex-col gap-2 items-end">
                         <div className="flex gap-2">
                            <input 
                                type="text" 
                                value={program} 
                                onChange={(e) => setProgram(e.target.value)}
                                className="text-right bg-amber-50 border border-amber-100 hover:border-amber-300 focus:border-amber-500 focus:outline-none text-amber-700 text-xs font-bold rounded-full px-3 py-1 uppercase tracking-wide w-24 md:w-auto"
                            />
                             <input 
                                type="text" 
                                value={yearLevel} 
                                onChange={(e) => setYearLevel(e.target.value)}
                                className="text-right bg-gray-100 border border-gray-200 hover:border-gray-300 focus:border-gray-500 focus:outline-none text-gray-600 text-xs font-bold rounded-full px-3 py-1 uppercase tracking-wide w-16 md:w-auto"
                            />
                         </div>
                         <span className="text-xs text-gray-400 font-bold uppercase tracking-widest">{user.enrollment_status}</span>
                     </div>
                </div>

                {/* Secondary Details (Contact/Address) */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-4 border-t border-gray-100">
                     <div className="p-3 rounded-xl hover:bg-gray-50 transition-colors group">
                        <label className="text-[10px] font-bold text-gray-400 uppercase flex items-center gap-1 mb-1">
                            <Mail size={12}/> Email Address
                        </label>
                        <input 
                            type="text" 
                            value={email} 
                            onChange={(e) => setEmail(e.target.value)}
                            className="w-full bg-transparent border-b border-transparent group-hover:border-gray-300 focus:border-luGreen focus:outline-none text-sm font-medium text-gray-700"
                        />
                     </div>
                     <div className="p-3 rounded-xl hover:bg-gray-50 transition-colors group">
                        <label className="text-[10px] font-bold text-gray-400 uppercase flex items-center gap-1 mb-1">
                            <Phone size={12}/> Contact Number
                        </label>
                        <input 
                            type="text" 
                            value={contactNo} 
                            onChange={(e) => setContactNo(e.target.value)}
                            className="w-full bg-transparent border-b border-transparent group-hover:border-gray-300 focus:border-luGreen focus:outline-none text-sm font-medium text-gray-700"
                        />
                     </div>
                     <div className="p-3 rounded-xl hover:bg-gray-50 transition-colors group">
                        <label className="text-[10px] font-bold text-gray-400 uppercase flex items-center gap-1 mb-1">
                            <MapPin size={12}/> Home Address
                        </label>
                        <input 
                            type="text" 
                            value={address} 
                            onChange={(e) => setAddress(e.target.value)}
                            className="w-full bg-transparent border-b border-transparent group-hover:border-gray-300 focus:border-luGreen focus:outline-none text-sm font-medium text-gray-700 truncate"
                            placeholder="Add address..."
                        />
                     </div>
                </div>
            </div>
        </div>

        <div className="p-8 space-y-8 bg-gray-50/30">

            {/* Resume Upload Section */}
            <div className="bg-white rounded-2xl p-6 border border-gray-200 relative overflow-hidden shadow-sm">
                <div className="flex flex-col md:flex-row gap-6 items-start relative z-10">
                    <div className="flex-grow">
                        <h4 className="text-lg font-bold text-gray-800 mb-2 flex items-center gap-2">
                            <FileText size={20} className="text-luGreen"/> Auto-fill with Resume
                        </h4>
                        <p className="text-sm text-gray-500 leading-relaxed mb-4">
                            Upload your latest resume (PDF) to automatically populate your education and employment history. 
                        </p>

                        {verificationWarning && (
                            <div className="mb-4 p-3 bg-amber-50 text-amber-800 rounded-lg text-sm flex items-start gap-2 border border-amber-200">
                                <AlertCircle size={16} className="mt-0.5 flex-shrink-0" />
                                <span>{verificationWarning}</span>
                            </div>
                        )}

                        {resumeUploaded ? (
                            <div className="flex items-center gap-4">
                                <div className="inline-flex items-center gap-2 px-3 py-1 bg-green-50 text-green-700 rounded-lg text-xs font-bold border border-green-200">
                                    <CheckCircle size={12} /> Resume On File
                                </div>
                                <button onClick={handleDeleteResume} className="text-xs text-red-500 font-bold hover:underline flex items-center gap-1">
                                    <Trash2 size={12} /> Remove File
                                </button>
                            </div>
                        ) : (
                            <div className="text-xs text-gray-500 italic">No resume uploaded yet.</div>
                        )}
                    </div>
                    <div className="w-full md:w-64 flex-shrink-0">
                        <div className="bg-gray-50 rounded-xl border border-dashed border-gray-300 p-1 hover:border-luGreen transition-colors">
                            <FileUpload 
                                onFileSelect={handleResumeUpload} 
                                isLoading={parsing} 
                                label={parsing ? "Analyzing..." : (resumeUploaded ? "Update Resume" : "Upload Resume")}
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* Profile Sections Accordion */}
            <div className="space-y-4">

                {/* 1. Educational Background */}
                <div className="border border-gray-200 rounded-2xl overflow-hidden bg-white shadow-sm">
                    <button 
                        onClick={() => toggleSection('education')}
                        className="w-full p-5 bg-white hover:bg-gray-50 transition-colors flex justify-between items-center"
                    >
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-green-100 text-luGreen rounded-lg"><School size={18} /></div>
                            <h4 className="font-bold text-gray-700">Educational Background</h4>
                        </div>
                        {activeSection === 'education' ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </button>
                    {activeSection === 'education' && (
                        <div className="p-6 bg-white animate-fade-in grid grid-cols-1 md:grid-cols-2 gap-6 border-t border-gray-100">
                            <div className="col-span-1 md:col-span-2 bg-green-50 p-3 rounded-lg text-xs text-green-800 border border-green-100 mb-2">
                                If you have multiple schools for a level (e.g. transferred), please include them in the school field separated by a slash (e.g. School A / School B).
                            </div>
                            {renderInput('education', 'primary_school', 'Primary School(s)')}
                            {renderInput('education', 'primary_year_graduated', 'Year Graduated / Duration')}
                            {renderInput('education', 'secondary_school', 'Secondary School(s)')}
                            {renderInput('education', 'secondary_year_graduated', 'Year Graduated / Duration')}
                            {renderInput('education', 'bachelors_degree', 'Bachelor\'s Degree')}
                            {renderInput('education', 'bachelors_year_graduated', 'Year Graduated')}
                            {renderInput('education', 'masters_degree', 'Master\'s Degree')}
                            {renderInput('education', 'masters_year_graduated_or_units', 'Year/Units')}
                            {renderInput('education', 'doctoral_degree', 'Doctoral Degree')}
                            {renderInput('education', 'doctoral_year_graduated_or_units', 'Year/Units')}

                            <div className="col-span-1 md:col-span-2 pt-4 border-t border-gray-100">
                                <h5 className="font-bold text-gray-800 text-sm mb-4">Professional License</h5>
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                    {renderInput('education', 'professional_license', 'License Name')}
                                    {renderInput('education', 'license_number', 'License Number')}
                                    {renderInput('education', 'license_date_passed', 'Date Passed', 'date')}
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* 2. Employment History (Multiple) */}
                <div className="border border-gray-200 rounded-2xl overflow-hidden bg-white shadow-sm">
                    <button 
                        onClick={() => toggleSection('employment')}
                        className="w-full p-5 bg-white hover:bg-gray-50 transition-colors flex justify-between items-center"
                    >
                         <div className="flex items-center gap-3">
                            <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Briefcase size={18} /></div>
                            <h4 className="font-bold text-gray-700">Employment History ({profileData.employment.length})</h4>
                        </div>
                        {activeSection === 'employment' ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </button>
                    {activeSection === 'employment' && (
                        <div className="p-6 bg-white animate-fade-in space-y-6 border-t border-gray-100">
                            {profileData.employment.map((emp, index) => (
                                <div key={index} className="p-4 border border-gray-200 rounded-xl relative hover:shadow-sm transition-shadow">
                                    <button 
                                        onClick={() => removeEmployment(index)}
                                        className="absolute top-2 right-2 p-1.5 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                                    >
                                        <X size={16} />
                                    </button>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                                        <div className="space-y-1">
                                            <label className="text-xs font-bold text-gray-500 uppercase">Employment Status</label>
                                            <select 
                                                value={emp.employment_status || ''}
                                                onChange={(e) => updateEmployment(index, 'employment_status', e.target.value)}
                                                className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none text-sm"
                                            >
                                                <option value="">Select...</option>
                                                <option value="Employed">Employed</option>
                                                <option value="Self-employed">Self-employed</option>
                                                <option value="Unemployed">Unemployed</option>
                                                <option value="Retired">Retired</option>
                                            </select>
                                        </div>
                                        {/* Dynamic Fields based on Status */}
                                        {emp.employment_status === 'Employed' && (
                                            <>
                                                <input placeholder="Company Name" className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 text-sm" value={emp.company_name || ''} onChange={(e) => updateEmployment(index, 'company_name', e.target.value)} />
                                                <input placeholder="Position" className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 text-sm" value={emp.position || ''} onChange={(e) => updateEmployment(index, 'position', e.target.value)} />
                                                <input type="date" placeholder="Date Hired" className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 text-sm" value={emp.date_hired || ''} onChange={(e) => updateEmployment(index, 'date_hired', e.target.value)} />
                                            </>
                                        )}
                                        {emp.employment_status === 'Self-employed' && (
                                            <>
                                                <input placeholder="Business Name" className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 text-sm" value={emp.business_name || ''} onChange={(e) => updateEmployment(index, 'business_name', e.target.value)} />
                                                <input placeholder="Business Type" className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 text-sm" value={emp.business_type || ''} onChange={(e) => updateEmployment(index, 'business_type', e.target.value)} />
                                            </>
                                        )}
                                        <div className="flex items-center gap-2">
                                            <input type="checkbox" checked={emp.is_current_job || false} onChange={(e) => updateEmployment(index, 'is_current_job', e.target.checked)} id={`curr-${index}`} />
                                            <label htmlFor={`curr-${index}`} className="text-sm text-gray-600">Current Job?</label>
                                        </div>
                                    </div>
                                </div>
                            ))}
                            <button onClick={addEmployment} className="w-full py-2 border-2 border-dashed border-gray-300 text-gray-500 rounded-xl hover:border-luGreen hover:text-luGreen font-bold text-sm transition-all flex items-center justify-center gap-2">
                                <Plus size={16} /> Add Employment Record
                            </button>
                        </div>
                    )}
                </div>

                {/* 3. Community Engagement (Multiple) */}
                <div className="border border-gray-200 rounded-2xl overflow-hidden bg-white shadow-sm">
                    <button 
                        onClick={() => toggleSection('community')}
                        className="w-full p-5 bg-white hover:bg-gray-50 transition-colors flex justify-between items-center"
                    >
                         <div className="flex items-center gap-3">
                            <div className="p-2 bg-red-100 text-red-600 rounded-lg"><Heart size={18} /></div>
                            <h4 className="font-bold text-gray-700">Community Engagement ({profileData.community.length})</h4>
                        </div>
                        {activeSection === 'community' ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </button>
                    {activeSection === 'community' && (
                        <div className="p-6 bg-white animate-fade-in space-y-4 border-t border-gray-100">
                             {profileData.community.map((comm, index) => (
                                <div key={index} className="p-4 border border-gray-200 rounded-xl relative hover:shadow-sm transition-shadow grid grid-cols-1 md:grid-cols-2 gap-4">
                                     <button 
                                        onClick={() => removeCommunity(index)}
                                        className="absolute top-2 right-2 p-1.5 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                                    >
                                        <X size={16} />
                                    </button>
                                    <input placeholder="Organization Name" className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 text-sm" value={comm.organization_name || ''} onChange={(e) => updateCommunity(index, 'organization_name', e.target.value)} />
                                    <input placeholder="Role / Position" className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 text-sm" value={comm.role || ''} onChange={(e) => updateCommunity(index, 'role', e.target.value)} />
                                    <input type="date" placeholder="Date Affiliated" className="w-full px-4 py-2 rounded-lg bg-gray-50 border border-gray-200 text-sm" value={comm.date_affiliated || ''} onChange={(e) => updateCommunity(index, 'date_affiliated', e.target.value)} />
                                </div>
                             ))}
                            <button onClick={addCommunity} className="w-full py-2 border-2 border-dashed border-gray-300 text-gray-500 rounded-xl hover:border-luGreen hover:text-luGreen font-bold text-sm transition-all flex items-center justify-center gap-2">
                                <Plus size={16} /> Add Engagement
                            </button>
                        </div>
                    )}
                </div>

                {/* 4. Graduate Attributes */}
                <div className="border border-gray-200 rounded-2xl overflow-hidden bg-white shadow-sm">
                    <button 
                        onClick={() => toggleSection('attributes')}
                        className="w-full p-5 bg-white hover:bg-gray-50 transition-colors flex justify-between items-center"
                    >
                         <div className="flex items-center gap-3">
                            <div className="p-2 bg-purple-100 text-purple-600 rounded-lg"><Star size={18} /></div>
                            <h4 className="font-bold text-gray-700">Graduate Attributes (Self-Rating)</h4>
                        </div>
                        {activeSection === 'attributes' ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </button>
                    {activeSection === 'attributes' && (
                        <div className="p-6 bg-white animate-fade-in border-t border-gray-100">
                            <p className="text-sm text-gray-500 mb-4">Please rate yourself on the following attributes (1 - Lowest, 5 - Highest).</p>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {renderRating('communication_skills', 'Communication Skills')}
                                {renderRating('problem_solving', 'Problem Solving')}
                                {renderRating('technical_skills', 'Technical Skills')}
                                {renderRating('teamwork', 'Teamwork')}
                                {renderRating('leadership', 'Leadership')}
                                {renderRating('ethics', 'Professional Ethics')}
                            </div>
                        </div>
                    )}
                </div>

            </div>

            {/* Actions */}
            <div className="pt-6 flex justify-end sticky bottom-0 bg-white p-4 border-t border-gray-100 z-10 shadow-[0_-5px_15px_-5px_rgba(0,0,0,0.05)] rounded-b-3xl">
                <button 
                    onClick={handleSaveProfile}
                    disabled={loading}
                    className="px-8 py-3 bg-luGreen text-white font-bold rounded-xl shadow-lg hover:bg-luGreen-dark hover:shadow-xl transition-all flex items-center justify-center gap-2"
                >
                    {loading ? (
                        <>
                            <Loader2 className="animate-spin w-5 h-5" />
                            <span>Saving...</span>
                        </>
                    ) : (
                        <>
                            <Save size={20} />
                            <span>Save Profile</span>
                        </>
                    )}
                </button>
            </div>

        </div>
    </div>
  );
};

export default MyProfilePage;
